Actionscript.script:
// the save slot bars container this will move up and down in the parent component
var bars = this._parent['bars'];

// keep track of how we're handling the scrolling
var mode:String = "none";

// this will be used to switch between the auto-animated scroll up/down
// click behavior and hodling the button down
var hold_timeout:Number;
var hold_delay:Number = 120;

// how long the auto-scroll animation will last on a simple up/down click
var ease_duration:Number = 200; // ms

// keeps track of when the eased auto-scroll animation starts
var ease_start:Number;

// these keep track of where an eased auto-scroll animation moves to and from
var ease_y_start:Number;
var ease_y_end:Number;

// what way are we scrolling during a button hold?
var scroll_dir:Number = 0;

// how many pixel per second to scroll when holding the up/down buttons
var scroll_speed:Number = 300;

// keeps tabs on the last time our timer executed
var last_exec_time:Number;

// tracks how far the mouse is from the top of the scroll bar when dragging
var drag_offset:Number;

// we have 10 bars total
var total_bars:Number = 10;

// we're showing 5 bars in the mask area
var visible_bars:Number = 5;

// this is how many bars we can scroll
var scroll_steps:Number = total_bars - visible_bars;

// how far we need to move to scroll a single bar
var bar_spacing:Number = bars['bar_1']._y - bars['bar_0']._y;

// calculate how many pixels it would take for the
// last bar to move up to where the lowest visible bar is
var bar_range:Number = bar_spacing * (total_bars - visible_bars);

// the lowest the bars clip can move down
var bar_max:Number = bars._y

// the highest the bars clip can move up
var bar_min:Number = bar_max - bar_range;

// how far the scroll bar can move
var scroll_range:Number = this.scroll_bottom._y - scroll_bar._y;

// highest position the scroll bar can move to
var scroll_min:Number = this.scroll_bar._y;

// lowest position the scroll bar can move to
var scroll_max:Number = scroll_min + scroll_range;

// how far the scroll_bar would move to scroll exactly 1 bar
var scrollStep:Number = scroll_range / scroll_steps;

// hide scroll_bottom
this.scroll_bottom._visible = false;

// --------------------- scroll behavior -----------------------\\

// changes the position of the bars clip in relation to where scroll_bar currently is
function updateBarsFromScroll():Void
{
    var percent:Number = (scroll_bar._y - scroll_min) / scroll_range;
    percent = Math.max(0, Math.min(1, percent));

    bars._y = bar_max - (percent * bar_range);
}

// -------------- stop any animations/update cycles ------------- \\
function stopMotion():Void
{
    mode = "none";

	// just in case this is still running...
    clearTimeout(hold_timeout);
    hold_timeout = 0;

	// and stop any of our frame based handlers
    this.onEnterFrame = null;
}

// -------------------- animation for simple up/down clicks ---------------- \\

// starts our automatic ease animation when a button is initially pressed
function startEase(direction):Void
{
	// end any existing motion handlers
	stopMotion();

	// we are going into ease mode
    mode = "ease";

	// record where the far is moving from, and where it is moving to
    ease_y_start = scroll_bar._y;
	ease_y_end = ease_y_start + (direction * scrollStep);

	// make sure we're staying in our scroll bounds
	ease_y_end = Math.max(scroll_min, Math.min(scroll_max, ease_y_end));

	// record when this animatin started so we can move it with delta time
    ease_start = getTimer();

	// start animating!
    this.onEnterFrame = easeUpdate;
}

// handles the ease animation
function easeUpdate():Void
{
	// figure out how much real time has passed, so we can move things at the same overall speed regardless of FPS
    var elapsed:Number = getTimer() - ease_start;

	// how far through the animation are we? (0 = just started, 1=finished)
    var anim_progress:Number = elapsed / ease_duration;

	// if the animation is finished...
    if (anim_progress >= 1)
    {
		// set the final position
        scroll_bar._y = ease_y_end;

		// endthe animation
        stopMotion();

		// sync the bars clip to the scroll position
        updateBarsFromScroll();
        return;
    }

	// use the cubic easing algo to get a 0-1 value indicating how far along our target distance we should be moved
    var eased:Number = easeInOutCubic(anim_progress);

	// calculate the new scrollbar position
    scroll_bar._y = ease_y_start + ((ease_y_end - ease_y_start) * eased);

	// sync the bars clip to the scroll position
    updateBarsFromScroll();
}

// calculates how far to scroll based on how far we are in the animation, to get a nice easing effect
function easeInOutCubic(progress:Number):Number
{
	// we're in the first half of the animation
    if (progress < 0.5)
    {
		// how far are we in this half?
        var ease_in_progress:Number = progress * 2;

		// use the cubic formula to get an eased distance at this progress value
        return (ease_in_progress * ease_in_progress * ease_in_progress) / 2;

	// we're in the second half of the animation
	} else {

        // how far are we in this half?
        var ease_out_progress:Number = (progress - 0.5) * 2;

        // use the cubic formula to get an eased distance at this progress value (this time it's inverted)
        var eased:Number = 1 - Math.pow(1 - ease_out_progress, 3);

        // add the inverted ease value to the half of the animation that's already finished
        return 0.5 + eased / 2;
    }
}

// --------------- handle holding the up/down buttons to keep scrolling ------------- \\

// when we have detected the button is being held....
function startHold(direction):Void
{
	// end any existing motion handlers
	stopMotion();

	// hold mode!
    mode = "hold";

	// record wich way we are scrolling
	scroll_dir = direction;

	// record the current time so we'll know how much has passed in our scroll handler
    last_exec_time = getTimer();

	// start the hold mode loop
    this.onEnterFrame = holdUpdate;
}

// handles scrolling while holding an up/down button
function holdUpdate():Void
{
	// calculate a delta modifier so the scroll has the same real-time speed regardless of FPS
    var now:Number = getTimer();
    var delta:Number = (now - last_exec_time) / 1000;

	// update this for the next loop
    last_exec_time = now;

	// move the scroll_bar
    scroll_bar._y += scroll_dir * scroll_speed * delta;

    // lock it to scroll bounds
    scroll_bar._y = Math.max(scroll_min, Math.min(scroll_max, scroll_bar._y));

	// synch the bars clip position
    updateBarsFromScroll();
}

// -------------------- handle pressing the up/down buttons ------------------ \\

// down button
function onUpDown():Void
{
	// assume this is a simple click for now nd start the ease animation
    startEase(-1);

	// start a timeout to see if we're still holding this button after a short duration
    hold_timeout = setTimeout(function()
    {
		// if we are, switch to hold mode
        startHold(-1);
    }, hold_delay);
}

// up button
function onDownDown():Void
{
	// assume this is a simple click for now nd start the ease animation
    startEase(1);

	// start a timeout to see if we're still holding this button after a short duration
    hold_timeout = setTimeout(function()
    {
		// if we are, switch to hold mode
        startHold(1);
    }, hold_delay);
}

// add listeners for when the up or down button are pressed
scroll_up.onPress = function() { onUpDown(); };
scroll_down.onPress = function() { onDownDown(); };

// ------------- scrollbar drag handling ---------------------- \\

// start dragging the scroll bar
function startDragScroll():Void
{
	// end any existing motion handlers
	stopMotion();

	// drag mode - ooh la la
    mode = "drag";

	// mak a note of where the mouse is in relation to the bar
    drag_offset = scroll_bar._y - _ymouse;

	// start the drag handling
    this.onEnterFrame = dragUpdate;
}

function dragUpdate():Void
{
	var lastY = scroll_bar._y;

	// move the scroll bar
    scroll_bar._y = _ymouse + drag_offset;

    // lock to bounds
    scroll_bar._y = Math.max(scroll_min, Math.min(scroll_max, scroll_bar._y));

	// if the bar actually moved, move the bars clip too
	if (scroll_bar._y !== lastY) updateBarsFromScroll();
}

// ass listener for when the scroll bar is grabbed
scroll_bar.onPress = function() { startDragScroll(); };

// -------- handle when mouse is released (covers ALL modes) ---------------\\

function onButtonUp():Void
{
    if (mode == "ease")
    {
		// we know we aren't holding anything, so clear this out
		clearTimeout(hold_timeout);

        // And let easing animation finish naturally
        return;
    }

    // Otherwise, stop any hold motion
    stopMotion();
}

// listen for ANY mouse release.  This will end all of our scrolling handlers
// TODO: AS2 has no global MOUSE_UP equivalent. Use onMouseUp on the clip itself.
this.onMouseUp = function() { onButtonUp(); };
